ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/demographics#>
PREFIX p: <http://ambrosia.example.org/demographics/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?partyname WHERE {
  ?d a :Districts .
  ?pl a :Dominating_Party .
  ?pl p:hasDistricts ?d .
  ?pl p:partyName ?partyname .
  ?d p:name ?name_f .
  FILTER(?name_f = "District C")
} }
  component_2: { SELECT ?ideologyname WHERE {
  ?d a :Districts .
  ?pl a :Prevalent_Ideology .
  ?pl p:hasDistricts ?d .
  ?pl p:ideologyName ?ideologyname .
  ?d p:name ?name_f .
  FILTER(?name_f = "District C")
} }
  full: { SELECT ?partyname ?ideologyname WHERE {
  ?d a :Districts .
  ?pl a :Dominating_Party .
  ?pl p:hasDistricts ?d .
  ?pi a :Prevalent_Ideology .
  ?pi p:hasDistricts ?d .
  ?pl p:partyName ?partyname .
  ?pi p:ideologyName ?ideologyname .
  ?d p:name ?name_f .
  FILTER(?name_f = "District C")
} }
}
